def add_question(session, category, level, qtype, question, options=None, correct="A"):
    options = options or ["", "", "", ""]
    session.add(
        Question(
            category=category,
            level=level,
            qtype=qtype,
            question=question,
            option_a=options[0],
            option_b=options[1],
            option_c=options[2],
            option_d=options[3],
            correct_option=correct
        )
    )


def build_bank(items, total):
    bank = []
    contexts = [
        "في بيئة عمل مؤسسية",
        "عند معالجة بلاغ تشغيلي",
        "ضمن مركز الدعم الفني",
        "عند متابعة بلاغ مؤثر",
        "في حالة تكرار المشكلة",
        "ضمن إجراءات الحوكمة",
        "عند وجود أكثر من مستخدم متأثر",
        "عند الحاجة إلى تصعيد فني",
        "ضمن بيئة تشغيل حرجة",
        "عند التعامل مع خدمة داخلية"
    ]

    for i in range(total):
        question, options, correct = items[i % len(items)]

        if i >= len(items):
            question = f"{question} {contexts[i % len(contexts)]}"

        bank.append((question, options, correct))

    return bank


def run():
    create_db_and_tables()
    session = next(get_session())

    session.query(User).delete()
    session.query(Question).delete()

    session.add(User(username="nimda", password="nimda"))

    for question, options, correct in build_bank(MEDIUM_ITEMS, 75):
        add_question(session, "support", "medium", "mcq", question, options, correct)

    for question, options, correct in build_bank(HARD_ITEMS, 75):
        add_question(session, "support", "hard", "mcq", question, options, correct)

    for level, question in ESSAYS:
        add_question(session, "support", level, "essay", question)

    session.commit()
    session.close()

    print("تم إنشاء بنك الأسئلة بنجاح")
    print("150 سؤال اختياري: 75 متوسط و75 صعب")
    print("الاختبار يسحب 28 سؤال اختياري و2 سؤال مقالي")
    print("زمن السؤال الاختياري: 40 ثانية")
    print("زمن السؤال المقالي: دقيقتان")
    print("بيانات لوحة الإدارة: nimda / nimda")


if __name__ == "__main__":
    run()
